import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../../utils/api';
import CommunitySetup from '../../components/CommunitySetup';

export default function CommunityAdminMembers() {
  const [community, setCommunity] = useState(null);
  const [noCommunity, setNoCommunity] = useState(false);
  const [members, setMembers] = useState([]);
  const [joinRequests, setJoinRequests] = useState([]);
  const [pendingAccounts, setPendingAccounts] = useState([]);
  const [tab, setTab] = useState('requests');
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');

  const fetchData = async () => {
    setLoading(true);
    try {
      const communityRes = await api.get('/communities/my/profile');
      const c = communityRes.data.data;
      setCommunity(c);
      setNoCommunity(false);
      const [membersRes, requestsRes, accountsRes] = await Promise.all([
        api.get(`/communities/${c._id}/members`),
        api.get(`/communities/${c._id}/join-requests`),
        api.get(`/users/community/${c._id}/pending-students`),
      ]);
      setMembers(membersRes.data.data || []);
      setJoinRequests(requestsRes.data.data || []);
      setPendingAccounts(accountsRes.data.data || []);
    } catch (err) {
      if (err.response?.status === 404) {
        setNoCommunity(true);
      } else {
        toast.error('Failed to load data');
      }
    } finally { setLoading(false); }
  };

  useEffect(() => { fetchData(); }, []);

  const handleRequest = async (requestId, action, userName) => {
    try {
      const endpoint = `/communities/${community._id}/join-requests/${requestId}/${action}`;
      await api.put(endpoint, action === 'reject' ? { reason: prompt('Rejection reason (optional):') || '' } : {});
      toast.success(`${userName}'s request ${action}ed`);
      fetchData();
    } catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
  };

  const removeMember = async (userId, name) => {
    if (!window.confirm(`Remove ${name} from this community?`)) return;
    try {
      await api.delete(`/communities/${community._id}/members/${userId}`);
      toast.success(`${name} removed`);
      fetchData();
    } catch { toast.error('Failed to remove member'); }
  };

  const filteredMembers = members.filter(m => 
    m.user?.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    m.user?.email?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    m.user?.itNumber?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  if (loading) return (
    <div className="loading-screen" style={{ 
      minHeight: '400px',
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '16px'
    }}>
      <div className="spinner" style={{ width: '40px', height: '40px', borderWidth: '3px' }} />
      <span style={{ color: 'var(--text-secondary)' }}>Loading member data...</span>
    </div>
  );

  return (
    <div className="page-wrapper" style={{ background: 'var(--bg-primary)', minHeight: '100vh' }}>
      <div className="container" style={{ maxWidth: 1200, margin: '0 auto', padding: '32px 20px' }}>

        {/* Enhanced Header */}
        <div className="page-header" style={{ marginBottom: 32 }}>
          <div style={{ 
            display: 'flex', 
            justifyContent: 'space-between', 
            alignItems: 'flex-start',
            flexWrap: 'wrap',
            gap: '16px'
          }}>
            <div>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '8px' }}>
                <div style={{ 
                  width: '48px', 
                  height: '48px', 
                  background: 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent))',
                  borderRadius: 'var(--radius-md)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: '24px'
                }}>
                  👥
                </div>
                <div>
                  <h2 style={{ fontFamily: 'var(--font-display)', margin: 0, fontSize: '1.75rem' }}>
                    MEMBER <span className="gradient-text">MANAGEMENT</span>
                  </h2>
                  <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem', marginTop: '4px' }}>
                    {community?.name} — Manage members and requests
                  </p>
                </div>
              </div>
            </div>
            <Link to="/community-admin" className="btn btn-outline" style={{ 
              display: 'flex',
              alignItems: 'center',
              gap: '8px'
            }}>
              <span>←</span> Dashboard
            </Link>
          </div>
        </div>

        {/* Enhanced Tabs */}
        <div style={{ 
          display: 'flex', 
          gap: '8px',
          marginBottom: '32px',
          borderBottom: '1px solid rgba(255,255,255,0.1)',
          paddingBottom: '0'
        }}>
          {[
            { id: 'requests', label: 'Pending Requests', icon: '⏳', count: joinRequests.length, color: 'var(--warning)' },
            { id: 'members', label: 'Current Members', icon: '👥', count: members.length, color: 'var(--purple-light)' },
            { id: 'accounts', label: 'Pending Accounts', icon: '📝', count: pendingAccounts.length, color: 'var(--cyan-accent)' }
          ].map(t => (
            <button
              key={t.id}
              onClick={() => setTab(t.id)}
              style={{
                padding: '12px 20px',
                background: 'none',
                border: 'none',
                color: tab === t.id ? t.color : 'var(--text-muted)',
                cursor: 'pointer',
                fontSize: '0.9rem',
                fontWeight: tab === t.id ? '600' : '400',
                borderBottom: tab === t.id ? `2px solid ${t.color}` : '2px solid transparent',
                transition: 'all 0.2s',
                display: 'flex',
                alignItems: 'center',
                gap: '8px'
              }}
            >
              <span>{t.icon}</span> {t.label}
              {t.count > 0 && (
                <span style={{ 
                  background: t.color,
                  color: t.id === 'requests' ? 'black' : 'white',
                  borderRadius: '100px', 
                  padding: '2px 8px', 
                  fontSize: '0.7rem',
                  fontWeight: 'bold'
                }}>
                  {t.count}
                </span>
              )}
            </button>
          ))}
        </div>

        {/* Pending Requests Tab */}
        {tab === 'requests' && (
          <div>
            {joinRequests.length === 0 ? (
              <div className="card" style={{ textAlign: 'center', padding: '64px 24px' }}>
                <div style={{ fontSize: '4rem', marginBottom: '16px' }}>✅</div>
                <div style={{ fontSize: '1.1rem', marginBottom: '8px' }}>No pending requests</div>
                <div style={{ color: 'var(--text-muted)' }}>All membership requests have been processed</div>
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                {joinRequests.map(req => (
                  <div key={req._id} className="card" style={{ 
                    padding: '20px',
                    transition: 'transform 0.2s',
                    borderLeft: `4px solid var(--warning)`
                  }}>
                    <div style={{ display: 'flex', alignItems: 'flex-start', gap: '16px', flexWrap: 'wrap' }}>
                      <div className="avatar avatar-lg" style={{ 
                        width: '56px', 
                        height: '56px', 
                        background: 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent))',
                        fontSize: '1.4rem'
                      }}>
                        {req.user?.name?.charAt(0)}
                      </div>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontWeight: 700, fontSize: '1rem', marginBottom: '4px' }}>{req.user?.name}</div>
                        <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginBottom: '4px' }}>{req.user?.email}</div>
                        {req.user?.itNumber && (
                          <div style={{ 
                            fontSize: '0.75rem', 
                            fontFamily: 'var(--font-mono)', 
                            color: 'var(--cyan-accent)',
                            background: 'rgba(6, 182, 212, 0.1)',
                            display: 'inline-block',
                            padding: '2px 8px',
                            borderRadius: 'var(--radius-sm)',
                            marginTop: '4px'
                          }}>
                            📋 {req.user.itNumber}
                          </div>
                        )}
                      </div>
                      <div style={{ textAlign: 'right' }}>
                        <div style={{ 
                          fontSize: '0.7rem', 
                          color: 'var(--text-muted)', 
                          marginBottom: '12px',
                          display: 'flex',
                          alignItems: 'center',
                          gap: '4px'
                        }}>
                          <span>📅</span> {new Date(req.createdAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                        </div>
                        <div style={{ display: 'flex', gap: '8px' }}>
                          <button 
                            onClick={() => handleRequest(req._id, 'approve', req.user?.name)} 
                            className="btn btn-success btn-sm" 
                            style={{ 
                              background: 'linear-gradient(135deg, #10b981, #059669)',
                              border: 'none'
                            }}
                          >
                            ✓ Approve
                          </button>
                          <button 
                            onClick={() => handleRequest(req._id, 'reject', req.user?.name)} 
                            className="btn btn-danger btn-sm" 
                            style={{ 
                              background: 'linear-gradient(135deg, #ef4444, #dc2626)',
                              border: 'none'
                            }}
                          >
                            ✗ Reject
                          </button>
                        </div>
                      </div>
                    </div>
                    {req.message && (
                      <div style={{ 
                        marginTop: '16px', 
                        padding: '12px 16px', 
                        background: 'var(--bg-elevated)', 
                        borderRadius: 'var(--radius-sm)', 
                        fontSize: '0.85rem', 
                        color: 'var(--text-secondary)', 
                        fontStyle: 'italic',
                        borderLeft: `3px solid var(--purple-light)`
                      }}>
                        "{req.message}"
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {/* Current Members Tab */}
        {tab === 'members' && (
          <div>
            {/* Search Bar */}
            <div style={{ marginBottom: '24px' }}>
              <div style={{ position: 'relative', maxWidth: '400px' }}>
                <input
                  type="text"
                  placeholder="Search members by name, email or IT number..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  style={{
                    width: '100%',
                    padding: '12px 16px 12px 40px',
                    background: 'var(--bg-elevated)',
                    border: '1px solid rgba(255,255,255,0.1)',
                    borderRadius: 'var(--radius-md)',
                    color: 'var(--text-primary)',
                    fontSize: '0.875rem'
                  }}
                />
                <span style={{ 
                  position: 'absolute', 
                  left: '12px', 
                  top: '50%', 
                  transform: 'translateY(-50%)',
                  fontSize: '1rem'
                }}>
                  🔍
                </span>
              </div>
            </div>

            {filteredMembers.length === 0 ? (
              <div className="card" style={{ textAlign: 'center', padding: '64px 24px' }}>
                <div style={{ fontSize: '4rem', marginBottom: '16px' }}>👥</div>
                <div style={{ fontSize: '1.1rem', marginBottom: '8px' }}>No members found</div>
                <div style={{ color: 'var(--text-muted)' }}>
                  {searchTerm ? 'Try a different search term' : 'Invite members to join your community'}
                </div>
              </div>
            ) : (
              <div className="table-wrapper" style={{ 
                overflowX: 'auto',
                borderRadius: 'var(--radius-lg)',
                border: '1px solid rgba(255,255,255,0.05)'
              }}>
                <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                  <thead>
                    <tr style={{ 
                      borderBottom: '1px solid rgba(255,255,255,0.1)',
                      background: 'var(--bg-elevated)'
                    }}>
                      <th style={{ padding: '16px', textAlign: 'left', fontWeight: 600, fontSize: '0.8rem', color: 'var(--text-muted)' }}>MEMBER</th>
                      <th style={{ padding: '16px', textAlign: 'left', fontWeight: 600, fontSize: '0.8rem', color: 'var(--text-muted)' }}>IT NUMBER</th>
                      <th style={{ padding: '16px', textAlign: 'left', fontWeight: 600, fontSize: '0.8rem', color: 'var(--text-muted)' }}>ROLE</th>
                      <th style={{ padding: '16px', textAlign: 'left', fontWeight: 600, fontSize: '0.8rem', color: 'var(--text-muted)' }}>JOINED</th>
                      <th style={{ padding: '16px', textAlign: 'left', fontWeight: 600, fontSize: '0.8rem', color: 'var(--text-muted)' }}>ACTIONS</th>
                    </tr>
                  </thead>
                  <tbody>
                    {filteredMembers.map((m, index) => (
                      <tr key={m._id || m.user?._id} style={{ 
                        borderBottom: index < filteredMembers.length - 1 ? '1px solid rgba(255,255,255,0.05)' : 'none',
                        transition: 'background 0.2s'
                      }}>
                        <td style={{ padding: '16px' }}>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                            <div className="avatar" style={{ 
                              width: '40px', 
                              height: '40px', 
                              background: 'linear-gradient(135deg, var(--purple-primary), var(--cyan-accent))'
                            }}>
                              {m.user?.name?.charAt(0)}
                            </div>
                            <div>
                              <div style={{ fontWeight: 600, fontSize: '0.875rem', marginBottom: '2px' }}>{m.user?.name}</div>
                              <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)' }}>{m.user?.email}</div>
                            </div>
                          </div>
                        </td>
                        <td style={{ padding: '16px' }}>
                          <span style={{ 
                            fontFamily: 'var(--font-mono)', 
                            fontSize: '0.78rem', 
                            color: 'var(--cyan-accent)',
                            background: 'rgba(6, 182, 212, 0.1)',
                            padding: '2px 8px',
                            borderRadius: 'var(--radius-sm)',
                            display: 'inline-block'
                          }}>
                            {m.user?.itNumber || '—'}
                          </span>
                        </td>
                        <td style={{ padding: '16px' }}>
                          <span className="badge badge-student" style={{ 
                            background: 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent))',
                            padding: '4px 12px'
                          }}>
                            {m.role || 'member'}
                          </span>
                        </td>
                        <td style={{ padding: '16px', fontSize: '0.78rem', color: 'var(--text-muted)' }}>
                          {m.joinedAt ? new Date(m.joinedAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }) : '—'}
                        </td>
                        <td style={{ padding: '16px' }}>
                          <button 
                            onClick={() => removeMember(m.user?._id, m.user?.name)} 
                            className="btn btn-sm btn-outline" 
                            style={{ 
                              borderColor: 'var(--danger)', 
                              color: 'var(--danger)',
                              padding: '4px 12px',
                              fontSize: '0.75rem'
                            }}
                          >
                            Remove
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        )}

        {/* Pending Accounts Tab */}
        {tab === 'accounts' && (
          <div>
            {pendingAccounts.length === 0 ? (
              <div className="card" style={{ textAlign: 'center', padding: '64px 24px' }}>
                <div style={{ fontSize: '4rem', marginBottom: '16px' }}>✅</div>
                <div style={{ fontSize: '1.1rem', marginBottom: '8px' }}>No pending accounts</div>
                <div style={{ color: 'var(--text-muted)' }}>All student accounts have been processed</div>
              </div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                {pendingAccounts.map(user => (
                  <div key={user._id} className="card" style={{ 
                    padding: '20px',
                    transition: 'transform 0.2s',
                    borderLeft: `4px solid var(--cyan-accent)`
                  }}>
                    <div style={{ display: 'flex', alignItems: 'flex-start', gap: '16px', flexWrap: 'wrap' }}>
                      <div className="avatar avatar-lg" style={{ 
                        width: '56px', 
                        height: '56px', 
                        background: 'linear-gradient(135deg, var(--cyan-accent), var(--purple-primary))',
                        fontSize: '1.4rem'
                      }}>
                        {user.name?.charAt(0)}
                      </div>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontWeight: 700, fontSize: '1rem', marginBottom: '4px' }}>{user.name}</div>
                        <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginBottom: '4px' }}>{user.email}</div>
                        {user.itNumber && (
                          <div style={{ 
                            fontSize: '0.75rem', 
                            fontFamily: 'var(--font-mono)', 
                            color: 'var(--cyan-accent)',
                            background: 'rgba(6, 182, 212, 0.1)',
                            display: 'inline-block',
                            padding: '2px 8px',
                            borderRadius: 'var(--radius-sm)',
                            marginTop: '4px'
                          }}>
                            📋 {user.itNumber}
                          </div>
                        )}
                        <div style={{ 
                          fontSize: '0.7rem', 
                          color: 'var(--text-muted)', 
                          marginTop: '8px',
                          display: 'flex',
                          alignItems: 'center',
                          gap: '4px'
                        }}>
                          <span>📅</span> Applied {new Date(user.createdAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
                        </div>
                      </div>
                      <div style={{ display: 'flex', gap: '12px', alignItems: 'center' }}>
                        <button
                          onClick={async () => {
                            try {
                              await api.put(`/users/${user._id}/approve`);
                              toast.success(`Account approved! ${user.name} can now login`);
                              fetchData();
                            } catch (err) { toast.error(err.response?.data?.message || 'Failed to approve'); }
                          }}
                          className="btn btn-success btn-sm"
                          style={{ 
                            background: 'linear-gradient(135deg, #10b981, #059669)',
                            border: 'none',
                            padding: '8px 16px'
                          }}
                        >
                          ✓ Approve Account
                        </button>
                        <button
                          onClick={async () => {
                            const reason = prompt('Rejection reason (optional):') || '';
                            try {
                              await api.put(`/users/${user._id}/reject`, { reason });
                              toast.success(`${user.name}'s account rejected`);
                              fetchData();
                            } catch (err) { toast.error(err.response?.data?.message || 'Failed to reject'); }
                          }}
                          className="btn btn-danger btn-sm"
                          style={{ 
                            background: 'linear-gradient(135deg, #ef4444, #dc2626)',
                            border: 'none',
                            padding: '8px 16px'
                          }}
                        >
                          ✗ Reject
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {/* Quick Stats Footer */}
        <div style={{ 
          marginTop: '40px',
          padding: '20px',
          background: 'var(--bg-elevated)',
          borderRadius: 'var(--radius-md)',
          display: 'flex',
          justifyContent: 'space-around',
          flexWrap: 'wrap',
          gap: '20px',
          border: '1px solid rgba(255,255,255,0.05)'
        }}>
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: 'var(--purple-light)' }}>
              {members.length}
            </div>
            <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>Total Members</div>
          </div>
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: 'var(--warning)' }}>
              {joinRequests.length}
            </div>
            <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>Pending Requests</div>
          </div>
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: 'var(--cyan-accent)' }}>
              {pendingAccounts.length}
            </div>
            <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>Pending Accounts</div>
          </div>
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: '#10b981' }}>
              {members.filter(m => m.role === 'admin').length}
            </div>
            <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>Admins</div>
          </div>
        </div>
      </div>
    </div>
  );
}
